namespace RecipeHub.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil, Salt", Steps = "1. Preheat oven to 475°F.\n2. Roll out dough on floured surface.\n3. Spread crushed tomatoes evenly.\n4. Add torn mozzarella pieces.\n5. Bake 12-15 minutes until crust is golden.\n6. Top with fresh basil and drizzle olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti in salted water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra pecorino.", AverageRating = 4.8, RatingCount = 20 },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Cream, Onion, Garlic, Ginger", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and garam masala.\n5. Simmer 15 minutes, add cream.\n6. Add chicken pieces and simmer 5 more minutes.", AverageRating = 4.7, RatingCount = 15 },
        new Recipe { Id = 4, Title = "Vegetable Biryani", Category = "Indian", Ingredients = "Basmati rice, Mixed vegetables, Biryani masala, Saffron, Fried onions, Ghee, Mint, Cilantro", Steps = "1. Soak rice for 30 minutes.\n2. Par-cook rice with whole spices.\n3. Sauté vegetables with biryani masala.\n4. Layer rice and vegetables in a pot.\n5. Add saffron milk and fried onions.\n6. Seal and cook on low heat for 25 minutes.", AverageRating = 4.3, RatingCount = 8 },
        new Recipe { Id = 5, Title = "Tacos al Pastor", Category = "Mexican", Ingredients = "Pork shoulder, Dried chiles, Pineapple, Onion, Cilantro, Corn tortillas, Lime", Steps = "1. Blend dried chiles with spices for marinade.\n2. Marinate sliced pork overnight.\n3. Grill pork with pineapple slices.\n4. Chop pork and pineapple into small pieces.\n5. Warm tortillas on a griddle.\n6. Assemble with onion, cilantro, and lime.", AverageRating = 4.6, RatingCount = 18 },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Red onion, Jalapeño, Cilantro, Tomato, Salt", Steps = "1. Halve and pit avocados.\n2. Mash to desired consistency.\n3. Dice onion, jalapeño, tomato, and cilantro.\n4. Fold into avocado with lime juice.\n5. Season with salt.\n6. Serve immediately with tortilla chips.", AverageRating = 4.4, RatingCount = 10 },
        new Recipe { Id = 7, Title = "Beef Stir-Fry", Category = "Asian", Ingredients = "Flank steak, Soy sauce, Sesame oil, Broccoli, Bell pepper, Garlic, Ginger, Cornstarch", Steps = "1. Slice beef thin and marinate in soy sauce and cornstarch.\n2. Heat wok until smoking.\n3. Stir-fry beef in batches, set aside.\n4. Stir-fry vegetables with garlic and ginger.\n5. Return beef to wok.\n6. Add sauce and toss until glazed.", AverageRating = 4.2, RatingCount = 9 },
        new Recipe { Id = 8, Title = "Pad Thai", Category = "Asian", Ingredients = "Rice noodles, Shrimp, Eggs, Bean sprouts, Peanuts, Tamarind paste, Fish sauce, Lime", Steps = "1. Soak rice noodles in warm water.\n2. Make sauce with tamarind, fish sauce, and sugar.\n3. Stir-fry shrimp, push aside, scramble eggs.\n4. Add drained noodles and sauce.\n5. Toss with bean sprouts.\n6. Serve with crushed peanuts and lime wedges.", AverageRating = 4.5, RatingCount = 14 },
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipe(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        if (stars < 1 || stars > 5) return;
        var recipe = GetRecipe(recipeId);
        if (recipe is null) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);
        recipe.RatingCount = _ratings[recipeId].Count;
        recipe.AverageRating = _ratings[recipeId].Average();
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        var newId = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(new Recipe
        {
            Id = newId,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}

