@page "/category/{CategoryName}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@CategoryName Recipes - RecipeHub</PageTitle>

<h1>@CategoryName Recipes</h1>

@if (recipes is null || recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-4">
                <div class="card h-100">
                    <div class="card-body">
                        <h4 class="card-title">@recipe.Title</h4>
                        <p class="card-text text-muted">
                            ⭐ @recipe.AverageRating.ToString("F1") (@recipe.RatingCount ratings)
                        </p>
                        <a href="/recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

<a href="/" class="btn btn-secondary mt-3">← Back to Categories</a>

@code {
    [Parameter]
    public string CategoryName { get; set; } = string.Empty;

    private IReadOnlyList<Recipe>? recipes;

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(CategoryName);
    }
}

@page "/recipe/{RecipeId:int}"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
    <a href="/" class="btn btn-secondary">← Back to Home</a>
}
else
{
    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <StarRating RecipeId="recipe.Id" CurrentRating="recipe.AverageRating" RatingCount="recipe.RatingCount" />

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.Contains('.') ? step[(step.IndexOf('.') + 1)..].Trim() : step;
            <li>@text</li>
        }
    </ol>

    <a href="/category/@recipe.Category" class="btn btn-secondary mt-3">← Back to @recipe.Category Recipes</a>
}

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipe(RecipeId);
    }
}

@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<div class="my-3 p-3 border rounded">
    <h5>Rate this recipe</h5>
    <div class="star-rating">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span class="star @(star <= selectedRating ? "selected" : "")"
                  @onclick="() => Rate(star)"
                  role="button"
                  title="@star star(s)">
                @(star <= selectedRating ? "★" : "☆")
            </span>
        }
    </div>
    @if (submitted)
    {
        <p class="text-success mt-2">Thanks for rating! You gave @selectedRating star(s).</p>
    }
    <p class="mt-2 text-muted">
        Average: ⭐ @CurrentRating.ToString("F1") (@RatingCount ratings)
    </p>
</div>

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.2s;
    }
    .star-rating .star.selected {
        color: #ffc107;
    }
    .star-rating .star:hover {
        color: #ffdb4d;
    }
</style>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public double CurrentRating { get; set; }

    [Parameter]
    public int RatingCount { get; set; }

    private int selectedRating;
    private bool submitted;

    private void Rate(int stars)
    {
        selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        var recipe = RecipeService.GetRecipe(RecipeId);
        if (recipe is not null)
        {
            CurrentRating = recipe.AverageRating;
            RatingCount = recipe.RatingCount;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="model.Title" />
        <ValidationMessage For="() => model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="model.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Mexican">Mexican</option>
            <option value="Asian">Asian</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
        <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="model.Ingredients" />
        <ValidationMessage For="() => model.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="model.Steps" />
        <ValidationMessage For="() => model.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        RecipeService.AddRecipe(model.Title, model.Category, model.Ingredients, model.Steps);
        successMessage = $"Recipe \"{model.Title}\" submitted successfully!";
        model = new();
    }

    public class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        [System.ComponentModel.DataAnnotations.StringLength(100, ErrorMessage = "Title must be under 100 characters")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

